import Foundation

struct CategoryContent16 {
    static let buildWithAI = CategoryData(
        id: "build_with_ai", name: "Build with AI", icon: "hammer.fill", colorName: "aiSecondary",
        description: "Learn how real apps and tools are built with AI",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 15,
        unlockRequirement: .completeCategoryMinimum("ai_tools")
    )

    static let lesson1 = LessonData(id: "bwa_l1", title: "What's an API?", description: "How apps talk to AI", categoryId: "build_with_ai", questions: [
        Question(id: "bwa1_q1", type: .multipleChoice, questionText: "What does API stand for?", options: ["Application Programming Interface", "Automated Program Installation", "Advanced Processing Intelligence", "Artificial Platform Integration"], correctAnswer: "Application Programming Interface", explanation: "An API (Application Programming Interface) is a set of rules that allows different software applications to communicate with each other. It is how apps connect to AI services like Claude or GPT."),
        Question(id: "bwa1_q2", type: .trueFalse, questionText: "An API key is like a password that identifies your app when it talks to an AI service.", options: ["True", "False"], correctAnswer: "True", explanation: "An API key is a unique identifier that authenticates your application when making requests to an AI service. It tracks usage, manages billing, and controls access — much like a password for your app."),
        Question(id: "bwa1_q3", type: .matchPairs, questionText: "Match each API concept to its description:", matchPairs: [
            MatchPair(term: "Request", definition: "What your app sends to the AI"),
            MatchPair(term: "Response", definition: "What the AI sends back"),
            MatchPair(term: "API Key", definition: "Your app's unique identifier"),
            MatchPair(term: "Endpoint", definition: "The URL where the AI service lives")
        ], explanation: "These are the building blocks of API communication. Your app sends a request with an API key to an endpoint, and receives a response from the AI service."),
        Question(id: "bwa1_q4", type: .scenarioJudgment, questionText: "A developer accidentally shares their AI API key in a public code repository on GitHub. Is this a problem?", options: ["Yes, anyone could use their key and run up charges", "No, API keys are meant to be shared publicly", "It depends on the programming language used"], correctAnswer: "Yes, anyone could use their key and run up charges", explanation: "Exposing API keys publicly is a serious security risk. Anyone who finds the key can make requests using your account, potentially running up large bills or accessing your data."),
        Question(id: "bwa1_q5", type: .fillInBlank, questionText: "When your app sends a prompt to an AI API, the AI processes it and returns a __________ containing the generated text.", options: ["response", "download", "screenshot", "backup"], correctAnswer: "response", explanation: "The AI service processes your request and returns a response, typically in JSON format, containing the generated text along with metadata like token usage and model information."),
        Question(id: "bwa1_q6", type: .multipleChoice, questionText: "Why do AI companies charge money for API access?", options: ["Running AI models requires expensive computing resources", "APIs are rare and difficult to create", "It is legally required to charge for all APIs", "AI companies only want to serve large corporations"], correctAnswer: "Running AI models requires expensive computing resources", explanation: "Large AI models like Claude, GPT, and Gemini require powerful GPU servers to run. API pricing helps cover the significant computational costs of processing millions of requests.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "bwa_l2", title: "Your First AI App", description: "Concepts behind building AI-powered tools", categoryId: "build_with_ai", questions: [
        Question(id: "bwa2_q1", type: .multipleChoice, questionText: "What is the simplest type of AI app a beginner could conceptually build?", options: ["A chatbot that answers questions about a specific topic", "A self-driving car system", "A complete medical diagnosis platform", "A real-time language translation earpiece"], correctAnswer: "A chatbot that answers questions about a specific topic", explanation: "A simple chatbot is a great first AI project. It uses an AI API to process user questions and return relevant answers, requiring minimal code compared to complex AI applications."),
        Question(id: "bwa2_q2", type: .trueFalse, questionText: "You need to train your own AI model from scratch to build an AI-powered app.", options: ["True", "False"], correctAnswer: "False", explanation: "Most AI apps use pre-trained models through APIs. Companies like Anthropic, OpenAI, and Google provide ready-to-use models so developers can build apps without training their own."),
        Question(id: "bwa2_q3", type: .sortOrder, questionText: "Put these steps for building a simple AI chatbot in order:", options: ["Test and refine the chatbot's responses", "Write code to send user messages to the AI API", "Choose an AI API service to use", "Design the user interface for the chat"], correctAnswers: ["Choose an AI API service to use", "Design the user interface for the chat", "Write code to send user messages to the AI API", "Test and refine the chatbot's responses"], explanation: "Building an AI app starts with selecting a service, designing how users will interact with it, connecting to the API, and then iterating to improve quality."),
        Question(id: "bwa2_q4", type: .multipleChoice, questionText: "What is a 'system prompt' in the context of building an AI chatbot?", options: ["Instructions that define how the AI should behave and respond", "The operating system the chatbot runs on", "A warning message shown when the system crashes", "The first message the user types"], correctAnswer: "Instructions that define how the AI should behave and respond", explanation: "A system prompt sets the AI's personality, rules, and context. For example, you might instruct: 'You are a helpful cooking assistant. Only answer questions about recipes and food.'"),
        Question(id: "bwa2_q5", type: .fillInBlank, questionText: "A __________ is a visual layout that users interact with to send messages and see AI responses.", options: ["user interface", "server room", "training dataset", "neural network"], correctAnswer: "user interface", explanation: "The user interface (UI) is the front-end of your AI app — buttons, text fields, chat bubbles — that makes it easy for people to interact with the AI without knowing anything about APIs or code."),
        Question(id: "bwa2_q6", type: .scenarioJudgment, questionText: "You are building a homework help chatbot and want to make sure it helps students learn rather than just giving them answers. What is the best approach?", options: ["Use the system prompt to instruct the AI to guide learning, not give direct answers", "Let the AI answer however it wants", "Block all homework-related questions entirely"], correctAnswer: "Use the system prompt to instruct the AI to guide learning, not give direct answers", explanation: "System prompts let you shape AI behavior. Instructing it to ask guiding questions, explain concepts, and encourage thinking — rather than giving direct answers — creates a learning tool.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "bwa_l3", title: "Training & Fine-Tuning", description: "How companies customize AI for their needs", categoryId: "build_with_ai", questions: [
        Question(id: "bwa3_q1", type: .multipleChoice, questionText: "What is 'fine-tuning' in the context of AI?", options: ["Taking a pre-trained model and training it further on specific data", "Adjusting the volume on an AI voice assistant", "Deleting parts of an AI model to make it smaller", "Running an AI model on faster hardware"], correctAnswer: "Taking a pre-trained model and training it further on specific data", explanation: "Fine-tuning adapts a general-purpose AI model for a specific task or domain by training it on additional specialized data, like medical texts or legal documents."),
        Question(id: "bwa3_q2", type: .trueFalse, questionText: "Training a large AI model from scratch typically requires millions of dollars in computing costs.", options: ["True", "False"], correctAnswer: "True", explanation: "Training frontier AI models costs tens to hundreds of millions of dollars due to the massive computing power required. This is why fine-tuning existing models is a more practical approach for most companies."),
        Question(id: "bwa3_q3", type: .matchPairs, questionText: "Match each training concept to its description:", matchPairs: [
            MatchPair(term: "Pre-training", definition: "Learning general knowledge from vast data"),
            MatchPair(term: "Fine-tuning", definition: "Specializing for a specific task or domain"),
            MatchPair(term: "Training data", definition: "The information the model learns from"),
            MatchPair(term: "Evaluation", definition: "Testing model performance after training")
        ], explanation: "AI training is a multi-stage process. Models are first pre-trained on broad data, then fine-tuned for specific purposes, using carefully curated training data, and evaluated for quality."),
        Question(id: "bwa3_q4", type: .fillInBlank, questionText: "RLHF stands for Reinforcement Learning from Human __________, a technique used to align AI with human preferences.", options: ["Feedback", "Functions", "Features", "Frameworks"], correctAnswer: "Feedback", explanation: "RLHF is a key technique used by Anthropic, OpenAI, and others where human reviewers rate AI outputs to help train models to be more helpful, harmless, and honest."),
        Question(id: "bwa3_q5", type: .scenarioJudgment, questionText: "A hospital wants to use AI to help analyze medical images. Should they use a general AI model or one fine-tuned on medical data?", options: ["A model fine-tuned on medical data for better accuracy", "A general model since it knows more overall", "It makes no difference for medical applications"], correctAnswer: "A model fine-tuned on medical data for better accuracy", explanation: "Medical applications require models fine-tuned on medical data for reliable performance. A general model lacks the specialized knowledge needed for accurate medical image analysis."),
        Question(id: "bwa3_q6", type: .multipleChoice, questionText: "Why is the quality of training data more important than the quantity?", options: ["Poor quality data teaches the model bad patterns and biases", "AI models can only accept a fixed amount of data", "More data always makes training slower with no benefit", "Data quality only matters for image models, not text models"], correctAnswer: "Poor quality data teaches the model bad patterns and biases", explanation: "Training on low-quality, biased, or incorrect data produces a model that reproduces those problems. All major AI labs invest heavily in data curation and quality assurance.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "bwa_l4", title: "AI Agents & Automation", description: "What AI agents are and how they use tools", categoryId: "build_with_ai", questions: [
        Question(id: "bwa4_q1", type: .multipleChoice, questionText: "What makes an AI 'agent' different from a regular AI chatbot?", options: ["An agent can take actions and use tools, not just generate text", "An agent has feelings and consciousness", "An agent runs on more expensive hardware", "An agent can only answer yes or no questions"], correctAnswer: "An agent can take actions and use tools, not just generate text", explanation: "AI agents can break down tasks, use tools (like web search, code execution, or file management), and take multi-step actions to accomplish goals, going beyond simple text generation."),
        Question(id: "bwa4_q2", type: .trueFalse, questionText: "AI agents can use tools like web browsers, calculators, and code interpreters to complete tasks.", options: ["True", "False"], correctAnswer: "True", explanation: "Modern AI agents can be equipped with tools that extend their capabilities beyond text generation. Tool use allows agents to search the web, run code, manage files, and interact with external services."),
        Question(id: "bwa4_q3", type: .sortOrder, questionText: "Put these steps of how an AI agent completes a task in order:", options: ["Execute actions using available tools", "Deliver the final result to the user", "Break the task into smaller steps", "Receive a goal from the user"], correctAnswers: ["Receive a goal from the user", "Break the task into smaller steps", "Execute actions using available tools", "Deliver the final result to the user"], explanation: "AI agents follow a plan-and-execute cycle: they receive a goal, decompose it into manageable steps, use tools to complete each step, and deliver the combined result."),
        Question(id: "bwa4_q4", type: .fillInBlank, questionText: "MCP, which stands for Model Context __________, is an open standard that helps AI agents connect to external tools and data sources.", options: ["Protocol", "Processing", "Platform", "Program"], correctAnswer: "Protocol", explanation: "The Model Context Protocol (MCP) is an open standard developed by Anthropic that provides a universal way for AI models to connect with external data sources and tools."),
        Question(id: "bwa4_q5", type: .matchPairs, questionText: "Match each agent capability to its example:", matchPairs: [
            MatchPair(term: "Tool use", definition: "Searching the web for current info"),
            MatchPair(term: "Multi-step reasoning", definition: "Planning a complex research task"),
            MatchPair(term: "Code execution", definition: "Running Python to analyze data"),
            MatchPair(term: "Memory", definition: "Remembering context across a session")
        ], explanation: "AI agents combine multiple capabilities to handle complex tasks that would be impossible for a simple chatbot, making them increasingly useful for real-world work."),
        Question(id: "bwa4_q6", type: .scenarioJudgment, questionText: "A company wants an AI agent to automatically send emails to customers without any human review. Is this a good idea?", options: ["No, human oversight is important for automated customer communications", "Yes, AI agents are always accurate and appropriate", "It depends on how fast the AI can type"], correctAnswer: "No, human oversight is important for automated customer communications", explanation: "AI agents should have human oversight, especially for customer-facing actions. Automated communications can contain errors, inappropriate content, or miss important context that a human would catch.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "bwa_l5", title: "Scaling AI Products", description: "How companies handle millions of AI users", categoryId: "build_with_ai", questions: [
        Question(id: "bwa5_q1", type: .multipleChoice, questionText: "What is a 'rate limit' in the context of AI APIs?", options: ["A restriction on how many requests you can make per minute", "The speed at which the AI generates text", "The maximum length of an AI response", "The cost per word of AI-generated content"], correctAnswer: "A restriction on how many requests you can make per minute", explanation: "Rate limits prevent any single user from overwhelming AI servers. They ensure fair access and system stability when millions of people use the service simultaneously."),
        Question(id: "bwa5_q2", type: .trueFalse, questionText: "Running AI models at scale is inexpensive because computers are cheap.", options: ["True", "False"], correctAnswer: "False", explanation: "Serving AI models at scale requires expensive GPU hardware, massive data centers, significant electricity, and specialized engineering teams. Major AI companies spend billions on infrastructure."),
        Question(id: "bwa5_q3", type: .matchPairs, questionText: "Match each scaling challenge to its solution:", matchPairs: [
            MatchPair(term: "Too many users at once", definition: "Load balancing across servers"),
            MatchPair(term: "High computing costs", definition: "Optimized model architectures"),
            MatchPair(term: "Slow response times", definition: "Caching and edge deployment"),
            MatchPair(term: "Server failures", definition: "Redundancy and backup systems")
        ], explanation: "Scaling AI products involves solving multiple technical challenges simultaneously. Companies like Anthropic and Google invest heavily in infrastructure to serve millions of users reliably."),
        Question(id: "bwa5_q4", type: .fillInBlank, questionText: "A __________ is a unit used to measure both the input and output of AI language models, roughly corresponding to parts of words.", options: ["token", "pixel", "byte", "frame"], correctAnswer: "token", explanation: "Tokens are the basic units that language models process. A token is roughly 3-4 characters or about three-quarters of a word. API pricing is typically based on the number of tokens processed."),
        Question(id: "bwa5_q5", type: .scenarioJudgment, questionText: "Your AI app suddenly gets featured on a popular website and traffic increases 100x overnight. What is the biggest immediate concern?", options: ["Your API rate limits and costs could spike dramatically", "The AI model will become smarter with more users", "Your app's icon might need updating", "Users will complain about the app's color scheme"], correctAnswer: "Your API rate limits and costs could spike dramatically", explanation: "A sudden surge in traffic can exhaust API rate limits and cause unexpected costs. Successful AI products need plans for scaling, including budget caps, queue systems, and infrastructure scaling."),
        Question(id: "bwa5_q6", type: .multipleChoice, questionText: "Why do some companies offer different 'tiers' of AI models (like smaller and larger versions)?", options: ["Smaller models are cheaper and faster, larger ones are more capable", "Smaller models are always better than larger ones", "Larger models are cheaper to run than smaller ones", "There is no meaningful difference between model sizes"], correctAnswer: "Smaller models are cheaper and faster, larger ones are more capable", explanation: "Companies offer model tiers so developers can choose the right balance of cost, speed, and capability. Simple tasks can use fast, cheap small models while complex tasks benefit from larger ones.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "bwa_l6", title: "The Future Builder", description: "Career paths and skills for the AI era", categoryId: "build_with_ai", questions: [
        Question(id: "bwa6_q1", type: .multipleChoice, questionText: "Which skill is MOST important for someone who wants to work in AI?", options: ["Strong problem-solving and critical thinking abilities", "Memorizing the names of all AI models", "Being able to type extremely fast", "Having the most expensive computer available"], correctAnswer: "Strong problem-solving and critical thinking abilities", explanation: "Problem-solving and critical thinking are foundational skills for AI careers. Technical skills can be learned, but the ability to think clearly about complex problems is essential and transferable."),
        Question(id: "bwa6_q2", type: .trueFalse, questionText: "You need a PhD to have a career working with AI.", options: ["True", "False"], correctAnswer: "False", explanation: "While some AI research roles benefit from advanced degrees, many AI careers — including prompt engineering, AI product management, data analysis, and AI application development — are accessible with various educational backgrounds."),
        Question(id: "bwa6_q3", type: .matchPairs, questionText: "Match each AI career to what it involves:", matchPairs: [
            MatchPair(term: "Prompt Engineer", definition: "Crafting effective AI instructions"),
            MatchPair(term: "ML Engineer", definition: "Building and deploying AI models"),
            MatchPair(term: "AI Ethics Researcher", definition: "Ensuring AI is fair and safe"),
            MatchPair(term: "Data Scientist", definition: "Analyzing data to find insights")
        ], explanation: "The AI industry offers diverse career paths beyond just building models. Roles span engineering, ethics, product design, research, policy, and more."),
        Question(id: "bwa6_q4", type: .scenarioJudgment, questionText: "A student is interested in AI but finds coding difficult. Should they give up on an AI-related career?", options: ["No, many AI careers do not require heavy coding", "Yes, coding is the only path into AI", "It depends on which university they attend"], correctAnswer: "No, many AI careers do not require heavy coding", explanation: "AI careers include roles in ethics, policy, product design, content creation, testing, sales, and management. While coding helps, many impactful AI careers focus on other skills."),
        Question(id: "bwa6_q5", type: .fillInBlank, questionText: "AI __________ is the ability to understand, use, and think critically about AI — a skill increasingly valued in every career field.", options: ["literacy", "density", "velocity", "gravity"], correctAnswer: "literacy", explanation: "AI literacy — understanding how AI works, its capabilities, and its limitations — is becoming essential across all professions, not just technology roles."),
        Question(id: "bwa6_q6", type: .sortOrder, questionText: "Put these steps for getting started in AI in a logical order:", options: ["Build projects to practice your skills", "Explore AI career paths that interest you", "Learn AI fundamentals and key concepts", "Share your work and connect with the AI community"], correctAnswers: ["Learn AI fundamentals and key concepts", "Explore AI career paths that interest you", "Build projects to practice your skills", "Share your work and connect with the AI community"], explanation: "Starting an AI journey follows a natural progression: learn the basics, discover what excites you, practice through projects, and grow through community engagement.")
    ], order: 5, difficulty: .advanced)
}
